'use client'
import React from "react"
import axios from "axios"
import { useRouter } from "next/navigation"
export default function Status({status,id}) {
    const router = useRouter()
    function activeHandler(){
        axios.patch(`http://localhost:5000/api/category/update-status/${id}`,{feild:"status"}).then(
            (response)=>{
              if(response.data.success){
                router.refresh()

              }
            }
        ).catch(
            (error)=>{
                console.log(error)
            }
        )

    }
  return (
    <td className="px-4 py-3">
                    <span onClick={activeHandler}
                      className={`cursor-pointer px-2 py-1 text-xs rounded-full ${
                        status === true
                          ? "text-green-500" : "text-red-600"
                      }`}
                    >
                      <div>
                        { status ? "Active" : "Inactive"}
                      </div>
                    </span>
                  </td>
  )
}
